fun solve(prices: Array<Long>, strategy: Array<Long>, k: Long): Long {
    val n = prices.size
    var originalProfit = 0L
    for (i in 0 until n) {
        originalProfit += strategy[i] * prices[i]
    }

    val prefixPrices = LongArray(n + 1)
    val prefixVal = LongArray(n + 1)
    prefixPrices[0] = 0
    prefixVal[0] = 0
    for (i in 0 until n) {
        prefixPrices[i + 1] = prefixPrices[i] + prices[i]
        prefixVal[i + 1] = prefixVal[i] + strategy[i] * prices[i]
    }

    val halfK = k / 2
    var maxDiff = 0L

    for (i in 0 until (n - k + 1)) {
        val sumSecond = prefixPrices[i + k] - prefixPrices[i + halfK]
        val originalContribution = prefixVal[i + k] - prefixVal[i]
        val diff = sumSecond - originalContribution
        if (diff > maxDiff) {
            maxDiff = diff
        }
    }

    return originalProfit + max(0L, maxDiff)
}
